import type {
  WorkerInbound,
  WorkerOutbound,
} from './protocol';
import type { BinarizerStrategy, DecoderStats, ScannerError } from '../types';

import DecoderWorker from '../worker/decoder.worker.ts?worker&inline';

export interface DecoderClientOptions {
  width: number;
  height: number;
  poolSize?: number;
  onDecoded?: (payload: string, stats: DecoderStats) => void;
  onFrameDone?: (stats: DecoderStats) => void;
  onError?: (err: ScannerError) => void;
}

interface PendingInit {
  resolve: () => void;
  reject: (e: Error) => void;
}

export class DecoderClient {
  private worker: Worker;
  private pool: Uint8ClampedArray[] = [];
  private bufferLength: number;
  private pending: PendingInit | null = null;
  private nextFrameId = 0;
  private opts: DecoderClientOptions;
  private inFlight = 0;

  constructor(opts: DecoderClientOptions) {
    this.opts = opts;
    this.bufferLength = opts.width * opts.height * 4;
    this.worker = new DecoderWorker();
    this.worker.onmessage = (ev: MessageEvent<WorkerOutbound>) => this.onMessage(ev.data);
    this.worker.onerror = (ev) => {
      this.opts.onError?.({
        code: 'worker_crashed',
        message: ev.message || 'worker error',
        cause: ev.error,
      });
    };

    const poolSize = Math.max(2, opts.poolSize ?? 3);
    for (let i = 0; i < poolSize; i++) {
      this.pool.push(new Uint8ClampedArray(this.bufferLength));
    }
  }

  init(): Promise<void> {
    return new Promise((resolve, reject) => {
      this.pending = { resolve, reject };
      const msg: WorkerInbound = {
        type: 'init',
        width: this.opts.width,
        height: this.opts.height,
      };
      this.worker.postMessage(msg);
    });
  }

  setStrategy(strategy: BinarizerStrategy): void {
    const msg: WorkerInbound = { type: 'set_strategy', strategy };
    this.worker.postMessage(msg);
  }

  /**
   * @returns 利用可能なバッファ。フレーム取得側はここに RGBA を書き込んで sendFrame に渡す
   */
  acquireBuffer(): Uint8ClampedArray | null {
    return this.pool.pop() ?? null;
  }

  /**
   * Worker が解析中のフレーム数（バックプレッシャ判定に利用）
   */
  pendingFrames(): number {
    return this.inFlight;
  }

  sendFrame(rgba: Uint8ClampedArray): boolean {
    if (rgba.length < this.bufferLength) {
      return false;
    }
    this.inFlight += 1;
    const msg: WorkerInbound = {
      type: 'frame',
      rgba,
      width: this.opts.width,
      height: this.opts.height,
      frameId: this.nextFrameId++,
    };
    this.worker.postMessage(msg, [rgba.buffer]);
    return true;
  }

  dispose(): void {
    const msg: WorkerInbound = { type: 'dispose' };
    this.worker.postMessage(msg);
    this.worker.terminate();
    this.pool = [];
  }

  private onMessage(msg: WorkerOutbound): void {
    switch (msg.type) {
      case 'ready':
        this.pending?.resolve();
        this.pending = null;
        break;
      case 'decoded':
        this.inFlight = Math.max(0, this.inFlight - 1);
        this.pool.push(msg.rgba);
        this.opts.onDecoded?.(msg.payload, msg.stats);
        break;
      case 'frame_done':
        this.inFlight = Math.max(0, this.inFlight - 1);
        this.pool.push(msg.rgba);
        this.opts.onFrameDone?.(msg.stats);
        break;
      case 'error':
        this.pending?.reject(new Error(msg.message));
        this.pending = null;
        this.opts.onError?.({
          code: (msg.code as ScannerError['code']) || 'unknown',
          message: msg.message,
        });
        break;
    }
  }
}
