import { ref, type Ref } from '@vue/composition-api';
import type { ScannerError } from '../types';

export interface UseCameraOptions {
  videoConstraints?: MediaTrackConstraints;
  preferZoom?: number;
  onError?: (err: ScannerError) => void;
}

export interface UseCameraReturn {
  stream: Ref<MediaStream | null>;
  active: Ref<boolean>;
  videoWidth: Ref<number>;
  videoHeight: Ref<number>;
  start: (video: HTMLVideoElement) => Promise<void>;
  stop: () => void;
}

const DEFAULT_CONSTRAINTS: MediaTrackConstraints = {
  facingMode: { ideal: 'environment' },
  width: { ideal: 1920 },
  height: { ideal: 1080 },
  frameRate: { ideal: 30 },
};

export function useCamera(opts: UseCameraOptions = {}): UseCameraReturn {
  const stream = ref<MediaStream | null>(null);
  const active = ref(false);
  const videoWidth = ref(0);
  const videoHeight = ref(0);

  async function start(video: HTMLVideoElement): Promise<void> {
    if (active.value) {
      return;
    }
    if (!navigator.mediaDevices?.getUserMedia) {
      const err: ScannerError = {
        code: 'camera_unavailable',
        message: 'getUserMedia is not available',
      };
      opts.onError?.(err);
      throw new Error(err.message);
    }

    const baseConstraints: MediaTrackConstraints = {
      ...DEFAULT_CONSTRAINTS,
      ...(opts.videoConstraints ?? {}),
    };

    let mediaStream: MediaStream;
    try {
      mediaStream = await navigator.mediaDevices.getUserMedia({
        audio: false,
        video: baseConstraints,
      });
    } catch (e) {
      try {
        mediaStream = await navigator.mediaDevices.getUserMedia({
          audio: false,
          video: {
            ...baseConstraints,
            width: { ideal: 1280 },
            height: { ideal: 720 },
          },
        });
      } catch (e2) {
        const err: ScannerError = {
          code: e instanceof DOMException && e.name === 'NotAllowedError'
            ? 'camera_denied'
            : 'camera_unavailable',
          message: e2 instanceof Error ? e2.message : String(e2),
          cause: e2,
        };
        opts.onError?.(err);
        throw e2;
      }
    }

    if (opts.preferZoom && opts.preferZoom > 1) {
      const track = mediaStream.getVideoTracks()[0];
      const caps = (track.getCapabilities?.() ?? {}) as MediaTrackCapabilities & {
        zoom?: { min: number; max: number; step: number };
      };
      if (caps.zoom) {
        const z = Math.min(Math.max(opts.preferZoom, caps.zoom.min), caps.zoom.max);
        try {
          await track.applyConstraints({ advanced: [{ zoom: z } as MediaTrackConstraintSet] });
        } catch {
          // ignore: zoom is best-effort
        }
      }
    }

    stream.value = mediaStream;
    video.srcObject = mediaStream;
    video.setAttribute('playsinline', 'true');
    video.muted = true;
    await video.play();

    videoWidth.value = video.videoWidth;
    videoHeight.value = video.videoHeight;
    active.value = true;
  }

  function stop(): void {
    if (stream.value) {
      stream.value.getTracks().forEach((t) => t.stop());
      stream.value = null;
    }
    active.value = false;
  }

  return { stream, active, videoWidth, videoHeight, start, stop };
}
